import React, { useState, useEffect } from 'react';
import API from '../api/axios';
import Navigation from '../components/Navigation';

const DepartmentMaster = () => {
    const [departments, setDepartments] = useState([]);
    const [formData, setFormData] = useState({ deptName: '', deptShortName: '' });
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [isEditing, setIsEditing] = useState(false);
    const [editId, setEditId] = useState(null);

    useEffect(() => { fetchDepartments(); }, []);

    const fetchDepartments = async () => {
        try {
            const { data } = await API.get('/master/department');
            setDepartments(data);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error fetching departments' });
        }
    };

    const handleEdit = (dept) => {
        setIsEditing(true);
        setEditId(dept._id);
        setFormData({ deptName: dept.deptName, deptShortName: dept.deptShortName });
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    const handleDelete = async (id) => {
        if (!window.confirm('Are you sure you want to delete this department?')) return;
        try {
            await API.delete(`/master/department/${id}`);
            fetchDepartments();
            setMessage({ type: 'success', text: '✓ Department deleted successfully!' });
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error deleting department' });
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            if (isEditing) {
                await API.put(`/master/department/${editId}`, formData);
                setMessage({ type: 'success', text: '✓ Department updated successfully!' });
            } else {
                await API.post('/master/department', formData);
                setMessage({ type: 'success', text: '✓ Department added successfully!' });
            }
            setFormData({ deptName: '', deptShortName: '' });
            setIsEditing(false);
            setEditId(null);
            fetchDepartments();
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: isEditing ? 'Error updating department' : 'Error adding department' });
        } finally {
            setLoading(false);
        }
    };

    const resetForm = () => {
        setFormData({ deptName: '', deptShortName: '' });
        setIsEditing(false);
        setEditId(null);
    };

    return (
        <div className="page-wrapper">
            <Navigation />
            <div className="content-area">
                <div className="header-section">
                    <h1 className="main-title">🏢 Department Master</h1>
                    <p className="subtitle">Manage all departments in the system</p>
                </div>

                {message && (
                    <div className={`alert ${message.type === 'success' ? 'alert-success' : 'alert-error'}`}>
                        {message.text}
                    </div>
                )}

                <div className="master-grid">
                    <div className="glass-card">
                        <form onSubmit={handleSubmit} className="form-body">
                            <h3 className="form-title">{isEditing ? '✏️ Edit Department' : '➕ Add New Department'}</h3>
                            <div className="form-group">
                                <label className="form-label">Department Name</label>
                                <input
                                    type="text" required
                                    value={formData.deptName}
                                    onChange={e => setFormData({ ...formData, deptName: e.target.value })}
                                    className="form-input"
                                    placeholder="Enter department name..."
                                />
                            </div>
                            <div className="form-group">
                                <label className="form-label">Short Name</label>
                                <input
                                    type="text" required
                                    value={formData.deptShortName}
                                    onChange={e => setFormData({ ...formData, deptShortName: e.target.value })}
                                    className="form-input"
                                    placeholder="e.g., IT, HR..."
                                    maxLength="10"
                                />
                            </div>
                            <div className="form-actions">
                                <button type="submit" disabled={loading} className="btn btn-primary" style={{ flex: 1 }}>
                                    {loading ? 'Processing...' : (isEditing ? 'Update Department' : '+ Add Department')}
                                </button>
                                {isEditing && (
                                    <button type="button" onClick={resetForm} className="btn btn-secondary">
                                        Cancel
                                    </button>
                                )}
                            </div>
                        </form>
                    </div>

                    <div className="table-card">
                        <h3 className="table-title">📋 Department List</h3>
                        <div className="table-scroll">
                            <table className="data-table">
                                <thead>
                                    <tr>
                                        <th>Name</th>
                                        <th>Short Name</th>
                                        <th style={{ textAlign: 'center' }}>Actions</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {departments.length > 0 ? (
                                        departments.map(dept => (
                                            <tr key={dept._id}>
                                                <td>{dept.deptName}</td>
                                                <td><span className="badge badge-primary">{dept.deptShortName}</span></td>
                                                <td className="table-actions">
                                                    <button onClick={() => handleEdit(dept)} className="btn-icon-only" title="Edit">✏️</button>
                                                    <button onClick={() => handleDelete(dept._id)} className="btn-icon-only text-error" title="Delete">🗑️</button>
                                                </td>
                                            </tr>
                                        ))
                                    ) : (
                                        <tr><td colSpan="3" className="table-empty">No departments found</td></tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default DepartmentMaster;
